import { NavLink } from "react-router-dom";
import React from "react";
import ScrollBtn from "./ScrollBtn";
import CartItem from "./CartItem";
import CartTotals from "./CartTotals";
export default class Cart extends React.Component {
  componentDidMount() {
    // this.props.getTotalPrice(this.props.cartItems);
  }
  
  render() {
    const {
      cartItems,
      selectedAttributes,
      handleAddProduct,
      handleRemoveProduct,
      successMsg,
      productsQuantity,
      totalPayment,
      taxes
  
    } = this.props;


    // console.log(cartItems)
    document.title = "Cart | Pizza Time";
    return (
      <>
      <article className="cart-container">
            <h1>Cart</h1>
        {cartItems.length === 0 ? (
        
            <section className="cart-title-section">
              <h3>Oh, no, your cart is empty</h3>
              <p>Seems like you have not added anything to your cart yet.</p>
              <NavLink to="/menu" className="back-to-menu">
                Check out menu
              </NavLink>
            </section>
      
        ) : (
          <section className="cart-title-section">
            {cartItems.map((cartItem) => (
              <CartItem
                successMsg={successMsg}
                cartItem={cartItem}
                selectedAttributes={selectedAttributes}
                handleAddProduct={handleAddProduct}
                handleRemoveProduct={handleRemoveProduct}
                className="cart-item"
              />
            ))}
          </section>
        )}
        <CartTotals productsQuantity={productsQuantity} totalPayment={totalPayment} taxes={taxes}/>
        </article>

        <ScrollBtn />
      </>
    );
  }
}

